// Implementation example drift detection helper
function driftScore(loadA, loadB) {
  const norm = arr => Math.sqrt(arr.reduce((s,v)=>s+v*v,0));
  const a = loadA.map((v,i)=> v / (norm(loadA) || 1));
  const b = loadB.map((v,i)=> v / (norm(loadB) || 1));
  let dot = 0;
  for (let i=0; i<Math.min(a.length,b.length); i++) dot += a[i]*b[i];
  return dot;
}
```

